157→export function exportSketchSvg(project) {
158→  const paper = PAPER_PRESETS.A4_LANDSCAPE;
159→  const pageW = paper.width;
160→  const pageH = paper.height;
161→
162→  const renderParts = project.parts.filter((p) => p.type !== 'dimension');
163→  const dimensions = project.parts.filter((p) => p.type === 'dimension');
164→
165→  if (renderParts.length === 0 && dimensions.length === 0) return null;
166→
167→  const views = ['top', 'front', 'side'];
168→  const viewLabels = { top: 'Top View', front: 'Front View', side: 'Side View' };
169→
170→  // Calculate bounds for each view (including dimensions)
171→  const boundsList = views.map((v) => getPartsBounds(renderParts, v, dimensions));
172→
173→  // Available area for 3 views side by side
174→  const availW = pageW - 2 * MARGIN;
175→  const availH = pageH - 2 * MARGIN - TITLE_HEIGHT - VIEW_GAP;
176→
177→  // Each view gets 1/3 of width
178→  const viewSlotW = (availW - 2 * VIEW_GAP) / 3;
179→  const viewSlotH = availH;
180→
181→  // Find uniform scale that fits all views
182→  let scale = Infinity;
183→  for (let i = 0; i < views.length; i++) {
184→    const b = boundsList[i];
185→    if (b.width > 0) scale = Math.min(scale, viewSlotW / b.width);
186→    if (b.height > 0) scale = Math.min(scale, viewSlotH / b.height);
187→  }
188→  if (!isFinite(scale) || scale <= 0) scale = 0.1;
189→
190→  // Build SVG
191→  let svgContent = '';
192→  svgContent += `<rect x="0" y="0" width="${pageW}" height="${pageH}" fill="white"/>\n`;
193→
194→  // Title block
195→  svgContent += `<text x="${pageW / 2}" y="${MARGIN + 6}" text-anchor="middle" font-family="sans-serif" font-size="5" font-weight="bold" fill="#333">${project.name || 'Untitled'}</text>\n`;
196→  svgContent += `<text x="${pageW - MARGIN}" y="${pageH - 4}" text-anchor="end" font-family="sans-serif" font-size="3" fill="#999">${new Date().toLocaleDateString()}</text>\n`;
197→
198→  // Render each view
199→  for (let i = 0; i < views.length; i++) {
200→    const view = views[i];
201→    const b = boundsList[i];
202→    const slotX = MARGIN + i * (viewSlotW + VIEW_GAP);
203→    const slotY = MARGIN + TITLE_HEIGHT + VIEW_GAP;
204→
205→    // Center within slot
206→    const renderedW = b.width * scale;
207→    const renderedH = b.height * scale;
208→    const offsetX = slotX + (viewSlotW - renderedW) / 2 - b.x * scale;
209→    const offsetY = slotY + (viewSlotH - renderedH) / 2 - b.y * scale;
210→
211→    // View label
212→    svgContent += `<text x="${slotX + viewSlotW / 2}" y="${slotY - 2}" text-anchor="middle" font-family="sans-serif" font-size="3.5" fill="#666">${viewLabels[view]}</text>\n`;
213→
214→    // View border
215→    svgContent += `<rect x="${slotX}" y="${slotY}" width="${viewSlotW}" height="${viewSlotH}" fill="none" stroke="#ddd" stroke-width="0.2"/>\n`;
216→
217→    // Parts
218→    svgContent += renderViewSvg(renderParts, view, offsetX, offsetY, scale);
219→
220→    // Dimensions
221→    svgContent += renderDimensionsSvg(dimensions, view, offsetX, offsetY, scale);
222→  }
223→
224→  // Page border
225→  svgContent += `<rect x="0.5" y="0.5" width="${pageW - 1}" height="${pageH - 1}" fill="none" stroke="#999" stroke-width="0.3"/>\n`;
226→
227→  const svg = `<?xml version="1.0" encoding="UTF-8"?>\n<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 ${pageW} ${pageH}" width="${pageW}mm" height="${pageH}mm">\n${svgContent}</svg>`;
228→
229→  return svg;
230→}
231→
232→export function downloadSketchSvg(project) {
233→  const svg = exportSketchSvg(project);
234→  if (!svg) return;
235→
236→  const blob = new Blob([svg], { type: 'image/svg+xml' });
237→  const url = URL.createObjectURL(blob);
238→  const a = document.createElement('a');
239→  a.href = url;
240→  a.download = `${project.name || 'sketch'}-sheet.svg`;
241→  document.body.appendChild(a);
242→  a.click();
243→  document.body.removeChild(a);
244→  URL.revokeObjectURL(url);
245→}
